  ('elementary-d0d1b9a2-moex-00320', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '有關財務報表分析，下列敘述何者正確？', '["流動比率大於1時，用現金償還應付帳款會使流動比率下降", "流動比率小於1時，賒購存貨會使流動比率上升", "速動比率小於1時，期末將已耗預付費用轉為費用，會使速動比率下降", "用現金償還短期借款，淨營運資金會減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
